async (params, browser) => {
  // Search for property
  await browser.open(`https://www.zillow.com/homes/${params.address}_rb/`)

  // Wait for estimates to load
  await browser.waitForSelector('[class*=\'zestimate\'], [class*=\'home-value\'], [data-testid=\'price\'], h1', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to value section
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract value estimates
  const estimate_data = await browser.evaluate(`const addressEl = document.querySelector('h1, [data-testid="bdp-address"], [class*="address"]'); const zestimateEl = document.querySelector('[class*="zestimate"] [class*="value"], [class*="Zestimate"], [data-testid="zestimate-value"]'); const rentEl = document.querySelector('[class*="rent-zestimate"], [class*="rentZestimate"]'); const rangeEl = document.querySelector('[class*="zestimate-range"], [class*="value-range"]'); const priceEl = document.querySelector('[data-testid="price"], [class*="price"] span'); const priceHistory = []; const historyRows = document.querySelectorAll('[class*="price-history"] tr, [class*="priceHistory"] tr'); historyRows.forEach(function(row) { const cells = row.querySelectorAll('td'); if (cells.length >= 3) { priceHistory.push({ date: cells[0] ? cells[0].textContent.trim() : '', event: cells[1] ? cells[1].textContent.trim() : '', price: cells[2] ? cells[2].textContent.trim() : '' }); } }); const taxEl = document.querySelector('[class*="tax"], [class*="property-tax"]'); const comparables = []; const compEls = document.querySelectorAll('[class*="comparable"] [class*="card"], [class*="comps"] [class*="card"]'); compEls.forEach(function(el) { const addrEl = el.querySelector('[class*="address"], address'); const prEl = el.querySelector('[class*="price"]'); const detailEl = el.querySelector('[class*="detail"], [class*="beds"]'); comparables.push({ address: addrEl ? addrEl.textContent.trim() : '', price: prEl ? prEl.textContent.trim() : '', details: detailEl ? detailEl.textContent.trim() : '' }); }); return { address: addressEl ? addressEl.textContent.trim() : '' + params.address + '', zestimate: zestimateEl ? zestimateEl.textContent.trim() : '', rent_estimate: rentEl ? rentEl.textContent.trim() : '', value_range: rangeEl ? rangeEl.textContent.trim() : '', list_price: priceEl ? priceEl.textContent.trim() : '', property_tax: taxEl ? taxEl.textContent.trim() : '', price_history: priceHistory.slice(0, 10), comparables: comparables.slice(0, 5), url: window.location.href }`)

  return estimate_data
}
